B.aqS=new A.hA('Bu kullan\u0131m ko\u015fullar\u0131, Koala by evlumba uygulamas\u0131n\u0131 ("Uygulama") kullan\u0131m\u0131n\u0131z\u0131 d\xfczenler. Uygulamay\u0131 kullanarak bu ko\u015fullar\u0131 kabul etmi\u015f say\u0131l\u0131rs\u0131n\u0131z.',null)
B.aqV=new A.hA("Son g\xfcncelleme: 18 Mart 2026",null)
B.arv=new A.hR("Hizmet Tan\u0131m\u0131",null)
B.aqO=new A.hA("Koala, yapay zeka destekli bir mekan analiz uygulamas\u0131d\u0131r. Kullan\u0131c\u0131lar soru foto\u011fraf\u0131 \xe7ekerek ad\u0131m ad\u0131m \xe7\xf6z\xfcm alabilir. Uygulama 9 farkl\u0131 bran\u015fta AI destekli \xf6\u011fretim hizmeti sunar.",null)
B.arr=new A.hR("Hesap ve Kay\u0131t",null)
B.aoN=new A.dX("Uygulamay\u0131 kullanmak i\xe7in Google veya telefon numaras\u0131 ile hesap olu\u015fturman\u0131z gerekir",null)
B.aoQ=new A.dX("Hesap bilgilerinizin do\u011fru ve g\xfcncel olmas\u0131ndan siz sorumlusunuz",null)
B.aoz=new A.dX("Hesab\u0131n\u0131z\u0131n g\xfcvenli\u011finden siz sorumlusunuz",null)
B.arA=new A.hR("Kredi Sistemi",null)
B.aox=new A.dX("Her yeni kullan\u0131c\u0131ya 10 \xfccretsiz kredi verilir",null)
B.aoW=new A.dX("Her mekan analizi 1 kredi harcar",null)
B.aoV=new A.dX("Ek kredi uygulama i\xe7i sat\u0131n alma ile edinilebilir",null)
B.aoU=new A.dX("Sat\u0131n al\u0131nan krediler iade edilemez",null)
B.ars=new A.hR("Kabul Edilebilir Kullan\u0131m",null)
B.aqL=new A.hA("Uygulamay\u0131 yaln\u0131zca ki\u015fisel mekan analizi ama\xe7l\u0131 kullanabilirsiniz. A\u015fa\u011f\u0131daki davran\u0131\u015flar yasakt\u0131r:",null)
B.aoT=new A.dX("Uygulamay\u0131 k\xf6t\xfcye kullanmak veya ba\u015fkalar\u0131n\u0131n kullan\u0131m\u0131n\u0131 engellemek",null)
B.aoM=new A.dX("Otomatik botlar veya scraper kullanmak",null)
B.aoP=new A.dX("Uygulamay\u0131 s\u0131nav s\u0131ras\u0131nda kopya \xe7ekmek i\xe7in kullanmak",null)
B.aoJ=new A.dX("Yasalara ayk\u0131r\u0131 i\xe7erik g\xf6ndermek",null)
B.art=new A.hR("Fikri M\xfclkiyet",null)
B.aqQ=new A.hA("Uygulama ve i\xe7eri\u011fi Evlumba Software'a aittir. AI taraf\u0131ndan \xfcretilen \xe7\xf6z\xfcmler e\u011fitim ama\xe7l\u0131d\u0131r ve do\u011frulu\u011fu garanti edilmez.",null)
B.arp=new A.hR("Sorumluluk S\u0131n\u0131rlamas\u0131",null)
B.aqZ=new A.hA('Koala bir mekan analiz asistan\u0131d\u0131r, profesyonel i\xe7 mimar\u0131n yerini almaz. AI \xf6nerilerinin do\u011frulu\u011fu garanti edilmez. Uygulama "oldu\u011fu gibi" sunulur.',null)
B.arx=new A.hR("De\u011fi\u015fiklikler",null)
B.aqR=new A.hA("Bu ko\u015fullar\u0131 zaman zaman g\xfcncelleyebiliriz. \xd6nemli de\u011fi\u015fikliklerde uygulama i\xe7i bildirim yapaca\u011f\u0131z.",null)
B.aqY=new A.hA("Kullan\u0131m ko\u015fullar\u0131yla ilgili sorular\u0131n\u0131z i\xe7in:\nE-posta: info@evlumba.com\nWeb: evlumba.com\nGeli\u015ftirici: Evlumba Software",null)
